import * as fs from 'fs';

import z from 'zod';

import { configFile } from './fs';
import { safeParseJson } from './neverthrow/json';

const ORIGINS_FILE = configFile('origins.json');

const userOriginSchema = z.object({
  url: z.string(),
  title: z.string(),
  description: z.string(),
  addedAt: z.string(),
});

const originsFileSchema = z.object({
  added: z.array(userOriginSchema),
});

export type UserOrigin = z.infer<typeof userOriginSchema>;

function readOriginsFile(): UserOrigin[] {
  if (!fs.existsSync(ORIGINS_FILE)) return [];
  const raw = fs.readFileSync(ORIGINS_FILE, 'utf-8');
  const json = safeParseJson('user-origins', raw);
  if (!json.isOk()) return [];
  const parsed = originsFileSchema.safeParse(json.value);
  return parsed.success ? parsed.data.added : [];
}

function writeOriginsFile(origins: UserOrigin[]): void {
  fs.writeFileSync(
    ORIGINS_FILE,
    JSON.stringify({ added: origins }, null, 2),
    'utf-8'
  );
}

export function loadUserOrigins(): UserOrigin[] {
  return readOriginsFile();
}

export function addUserOrigin(origin: Omit<UserOrigin, 'addedAt'>): UserOrigin {
  const origins = readOriginsFile();
  const entry: UserOrigin = { ...origin, addedAt: new Date().toISOString() };
  const existing = origins.findIndex(o => o.url === origin.url);
  if (existing >= 0) {
    origins[existing] = entry;
  } else {
    origins.push(entry);
  }
  writeOriginsFile(origins);
  return entry;
}

export function removeUserOrigin(url: string): { removed: boolean } {
  const origins = readOriginsFile();
  const filtered = origins.filter(o => o.url !== url);
  if (filtered.length === origins.length) return { removed: false };
  writeOriginsFile(filtered);
  return { removed: true };
}
